-- Step 1: Delete all existing justifications
DELETE FROM justifications;

-- Step 2: Drop the old unique constraint
ALTER TABLE justifications DROP INDEX justifications_programId_gaId_unique;

-- Step 3: Add competencyId column
ALTER TABLE justifications ADD COLUMN competencyId INT NOT NULL AFTER gaId;

-- Step 4: Add foreign key constraint for competencyId
ALTER TABLE justifications ADD CONSTRAINT justifications_competencyId_fk 
FOREIGN KEY (competencyId) REFERENCES competencies(id) ON DELETE CASCADE;

-- Step 5: Add new unique constraint
ALTER TABLE justifications ADD UNIQUE justifications_programId_competencyId_unique (programId, competencyId);

